 1→export type SessionTag =
 2→	| "research"
 3→	| "new_feature"
 4→	| "bug_fix"
 5→	| "refactoring"
 6→	| "documentation"
 7→	| "tests"
 8→	| "other";
 9→
10→export const SESSION_TAGS: readonly SessionTag[] = [
11→	"research",
12→	"new_feature",
13→	"bug_fix",
14→	"refactoring",
15→	"documentation",
16→	"tests",
17→	"other",
18→] as const;
19→
20→export interface SubagentFile {
21→	agentId: string;
22→	content: string;
23→}
24→
25→export interface IngestRequest {
26→	sessionId: string;
27→	projectPath: string;
28→	repository?: string;
29→	gitBranch?: string;
30→	gitSha?: string;
31→	tag?: SessionTag;
32→	content: string;
33→	subagents?: SubagentFile[];
34→}
35→
36→export interface UploadResult {
37→	success: boolean;
38→	status?: number;
39→	error?: string;
40→}
41→
42→export const DEFAULT_ENDPOINT = "https://rudel.numia.workers.dev/rpc";
